import json

def validate_iam_policy(policy_str):
    try:
        policy = json.loads(policy_str)

        # Check for top-level keys
        if 'Version' not in policy:
            return False
        if 'Statement' not in policy:
            return False

        statements = policy['Statement']

        # Ensure Statement is a list (standard AWS format) or has at least one valid statement
        if isinstance(statements, list):
            count = 0
            for stmt in statements:
                if 'Effect' not in stmt or 'Action' not in stmt:
                    continue
                count += 1
            return count > 0
        elif isinstance(statements, dict):
             # Handle legacy format where Statement is a single object or list of dicts
             if isinstance(statements, list):
                 for stmt in statements:
                     if 'Effect' not in stmt or 'Action' not in stmt:
                         continue
                     return True
             else:
                  if 'Effect' not in statements or 'Action' not in statements:
                      return False

        return False
    except json.JSONDecodeError:
        return False

# Example usage for validation logic demonstration
if __name__ == "__main__":
    policy = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Action": ["s3:GetObject"],
                "Resource": "*"
            }
        ]
    }

    valid = validate_iam_policy(json.dumps(policy))
    print(valid) # Should output True
